// One item per file (the SplitInBatches downstream will group them in chunks of batchSize).
const cfg = $input.first().json;
const files = Array.isArray(cfg.files) ? cfg.files : [];
return files.map(f => ({ json: { id: f.id, name: f.name, mimeType: f.mimeType || 'image/jpeg', shard_id: cfg.shard_id, run_id: cfg.run_id } }));

// Convert each binary into base64 + re-attach original file metadata
// (Drive Download replaces the item, so we look up {id,name,shard_id,run_id}
//  from Fan Out Files via itemMatching on the paired index).
const items = $input.all();
const out = [];
for (let i = 0; i < items.length; i++) {
  const it = items[i];
  let orig = {};
  try { orig = $('Fan Out Files').itemMatching(i).json || {}; } catch(e) { orig = it.json || {}; }
  let imageBase64 = null, imageMimeType = null;
  try {
    const buf = await this.helpers.getBinaryDataBuffer(i, 'data');
    imageBase64 = buf.toString('base64');
    imageMimeType = (it.binary && it.binary.data && it.binary.data.mimeType) || orig.mimeType || 'image/jpeg';
  } catch(e) {
    out.push({ json: { ...orig, _download_error: String(e) } });
    continue;
  }
  out.push({ json: { ...orig, imageBase64, imageMimeType } });
}
return out;

// Build the Gemini generateContent body (per item) with structured output + classification prompt.
const cfg = $('Config').first().json;
const inp = $json;
if (inp._download_error) {
  return { json: { ...inp, _skip_llm: true } };
}
const prompt = `RUOLO\nSei un sistema esperto nell'analisi di immagini di confezioni di cibo o bevande in contesto e-commerce.\n\nOBIETTIVO\nDevi classificare l'orientamento della confezione nella foto scegliendo una sola tra queste categorie: frontale, Di 3 quarti verso sinistra, Di 3 quarti verso destra, posteriore, Dall'alto, Dal basso.\n\nDEFINIZIONI\n- frontale: logo completamente visibile, centrato, lati assenti o minimi.\n- Di 3 quarti verso sinistra: logo visibile ma non perfettamente centrato; parte laterale sinistra >= 15%.\n- Di 3 quarti verso destra: come sopra ma lato destro.\n- posteriore: logo non visibile, presenti informazioni nutrizionali / barcode / retro etichetta.\n- Dall'alto: visibile tappo o apertura, superficie sotto, testi poco leggibili.\n- Dal basso: visibile parte inferiore, oggetto puo sembrare sospeso.\n\nREGOLE\n- Scegli una sola categoria, non inventare.\n- Usa '3 quarti' solo se il lato e chiaramente visibile (>=15%); se minimo -> frontale.\n- Logo centrato non distorto -> frontale.\n- Logo non visibile -> posteriore.\n- Angolo verticale evidente -> Dall'alto o Dal basso.\n- In dubbio tra frontale e 3 quarti -> frontale.\n\nCONFIDENCE 0-100: 90-100 molto sicuro, 70-89 abbastanza sicuro, 50-69 incerto, <50 molto incerto.\nNEEDS_HUMAN_REVIEW: true se confidence < 70, false se >= 70.`;
const body = {
  contents: [{
    parts: [
      { inline_data: { mime_type: inp.imageMimeType, data: inp.imageBase64 } },
      { text: prompt }
    ]
  }],
  generationConfig: {
    temperature: 0,
    maxOutputTokens: 256,
    responseMimeType: 'application/json',
    responseJsonSchema: {
      type: 'object',
      properties: {
        output:             { type: 'string', enum: ['frontale','Di 3 quarti verso sinistra','Di 3 quarti verso destra','posteriore',"Dall'alto",'Dal basso'] },
        confidence:         { type: 'integer', minimum: 0, maximum: 100 },
        needs_human_review: { type: 'boolean' }
      },
      required: ['output','confidence','needs_human_review']
    }
  }
};
return { json: { ...inp, _gemini_body: body, _model: cfg.geminiModel } };

// Per-item parser: emits exactly one row formatted for the sheet.
function safeParse(s){
  if (!s) return null;
  let t = String(s).trim();
  const m = t.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (m) t = m[1].trim();
  try { return JSON.parse(t); } catch(e){}
  const a=t.indexOf('{'),b=t.lastIndexOf('}');
  if (a>=0&&b>a){ try{ return JSON.parse(t.slice(a,b+1)); }catch(e){} }
  return null;
}
const VALID = ['frontale','Di 3 quarti verso sinistra','Di 3 quarti verso destra','posteriore',"Dall'alto",'Dal basso'];
const inp = $json;
let orig = {};
try { orig = $('Fan Out Files').itemMatching($itemIndex).json || {}; } catch(e) { orig = {}; }
const id = orig.id || inp.id || '';
const name = orig.name || inp.name || '';
const run_id = orig.run_id || inp.run_id || '';
const shard_id = orig.shard_id || inp.shard_id || '';
let output = '', confidence = 0, needs_human_review = true, parsing_error = null;
if (inp._download_error) {
  output = 'ERRORE_DOWNLOAD'; parsing_error = inp._download_error;
} else {
  const respRoot = inp.candidates ? inp : (inp.body || {});
  const choices = respRoot.candidates || [];
  let rawText = '';
  if (choices[0] && choices[0].content && choices[0].content.parts) {
    rawText = (choices[0].content.parts.map(p => p.text || '').join(' ') || '').trim();
  }
  const parsed = safeParse(rawText);
  if (parsed && typeof parsed === 'object') {
    output = String(parsed.output ?? parsed.orientamento ?? '').trim();
    confidence = Math.max(0, Math.min(100, Number(parsed.confidence ?? 0) || 0));
    needs_human_review = (typeof parsed.needs_human_review === 'boolean') ? parsed.needs_human_review : (confidence < 70);
    if (!VALID.includes(output)) {
      parsing_error = `categoria_non_valida:${output}`;
      output = 'ERRORE_VALIDAZIONE';
      confidence = 0; needs_human_review = true;
    }
  } else {
    parsing_error = 'json_malformato';
    output = 'NON_DETERMINATO';
  }
}
return { json: {
  ID: id,
  'Nome immagine': name,
  Classificazione: output,
  Confidence: confidence,
  Cluster: needs_human_review ? 'review' : 'auto',
  run_id, shard_id,
  parsing_error
}};
